from elftools.elf.elffile import ELFFile
from elftools.dwarf.descriptions import describe_form_class

# Addresses from the crash (PC offsets in libmonosgen-2.0.so)
addresses = [0x222098, 0x2241ac, 0x1abc80, 0x1abd14, 0x16dfa4, 0x16db6c, 0x16de04]
frame_nums = [1, 2, 3, 4, 5, 6, 7]

with open('libmonosgen-2.0.so.debug', 'rb') as f:
    elf = ELFFile(f)

    if not elf.has_dwarf_info():
        print("No DWARF info found!")
        exit(1)

    dwarf = elf.get_dwarf_info()

    # Use .symtab for function names
    symtab = elf.get_section_by_name('.symtab')
    if symtab is None:
        symtab = elf.get_section_by_name('.dynsym')

    def find_function(addr):
        """Find function name from symbol table."""
        best = None
        if symtab:
            for sym in symtab.iter_symbols():
                if sym['st_info']['type'] == 'STT_FUNC':
                    start = sym['st_value']
                    size = sym['st_size']
                    if start <= addr < start + size:
                        if best is None or start > best[1]:
                            best = (sym.name, start, size)
        return best

    def find_line(addr):
        """Find source file and line from DWARF line program."""
        for cu in dwarf.iter_CUs():
            lp = dwarf.line_program_for_CU(cu)
            if lp is None:
                continue
            prev_state = None
            for entry in lp.get_entries():
                if entry.state is None:
                    continue
                if prev_state and prev_state.address <= addr < entry.state.address:
                    fname = lp['file_entry'][prev_state.file - 1].name
                    if isinstance(fname, bytes):
                        fname = fname.decode('utf-8', errors='replace')
                    return fname, prev_state.line
                if entry.state.end_sequence:
                    prev_state = None
                else:
                    prev_state = entry.state
        return None, None

    print("=" * 90)
    print(f"{'Frame':<7} {'Offset':<12} {'Function':<45} {'Source'}")
    print("=" * 90)

    for i, addr in zip(frame_nums, addresses):
        func_info = find_function(addr)
        func_name = func_info[0] if func_info else "??"
        func_offset = f"+0x{addr - func_info[1]:x}" if func_info else ""

        src_file, src_line = find_line(addr)
        src = f"{src_file}:{src_line}" if src_file else "??"

        print(f"#{i:<6} 0x{addr:08x}  {func_name}{func_offset:<45s} {src}")

    print("=" * 90)
PYEOF

